const records = $input.first().json.records || [];

const migrations = records.map(r => {
  const f = r.fields;
  const taskName = f['Task'] || f[Object.keys(f)[0]] || '';
  const domain = taskName.replace(/^Migrate:\s*/i, '').trim();

  const notes = f['Notes'] || '';

  // Parse pipelineStage from notes
  let pipelineStage = null;
  const stageMatch = notes.match(/<!-- pipelineStage: ([\w-]+) -->/);
  if (stageMatch) pipelineStage = stageMatch[1];

  // Parse stageData from notes
  let stageData = null;
  try {
    const dataMatch = notes.match(/<!-- stageData: (\{.*?\}) -->/);
    if (dataMatch) stageData = JSON.parse(dataMatch[1]);
  } catch(e) {}

  // Parse migrationMeta from notes
  let meta = {};
  try {
    const metaMatch = notes.match(/<!-- migrationMeta: (\{.*?\}) -->/);
    if (metaMatch) meta = JSON.parse(metaMatch[1]);
  } catch(e) {}

  // Strip metadata comments for human-readable notes
  const humanNotes = notes.replace(/<!-- \w+: .*? -->/g, '').trim();

  // Map status
  const statusMap = { 'To Do': 'Queued', 'In Progress': null, 'Done': 'Live', 'Blocked': 'Issues' };
  const status = pipelineStage || statusMap[f['Status']] || f['Status'] || 'Queued';

  return {
    id: r.id,
    domain,
    client: meta.client || domain,
    status,
    notes: humanNotes,
    stageData,
    pilot: meta.pilot || false,
    test: meta.test || false,
    hasEmail: meta.hasEmail || false,
    ghlContactEmail: meta.ghlContactEmail || null,
    currentSub: meta.currentSub || 0,
    priority: f['Priority'] || null,
    assignee: f['Assignee'] || null,
    dueDate: f['Due Date'] || null
  };
}).filter(m => m.domain);

return [{
  json: {
    success: true,
    timestamp: new Date().toISOString(),
    count: migrations.length,
    migrations
  }
}];
